-- ============================================================
-- ARSIPARIS RI — Supabase Database Setup
-- Jalankan di: Supabase Dashboard → SQL Editor
-- ============================================================

-- 1. TABEL UTAMA
-- ============================================================
create table if not exists public.instansi (
  id          bigserial primary key,
  nama        text        not null,
  kategori    text        not null,
  provinsi    text,
  status      text        not null default 'Belum Ada Rekomendasi',
  tahun       int,
  keterangan  text        default '',
  terampil    int         not null default 0,
  mahir       int         not null default 0,
  penyelia    int         not null default 0,
  ahli_pertama int        not null default 0,
  ahli_muda   int         not null default 0,
  ahli_madya  int         not null default 0,
  ahli_utama  int         not null default 0,
  total       int         not null default 0,
  created_at  timestamptz default now(),
  updated_at  timestamptz default now()
);

-- 2. AUTO UPDATE updated_at
-- ============================================================
create or replace function public.set_updated_at()
returns trigger language plpgsql as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

drop trigger if exists trg_instansi_updated_at on public.instansi;
create trigger trg_instansi_updated_at
  before update on public.instansi
  for each row execute function public.set_updated_at();

-- 3. ROW LEVEL SECURITY (RLS)
-- ============================================================
alter table public.instansi enable row level security;

-- Semua orang bisa baca (public dashboard)
create policy "read_public" on public.instansi
  for select using (true);

-- Hanya authenticated (admin login) yang bisa insert/update/delete
create policy "write_authenticated" on public.instansi
  for all using (auth.role() = 'authenticated');

-- 4. TABEL ADMIN (custom auth — selain Supabase Auth)
-- ============================================================
create table if not exists public.admin_users (
  id         bigserial primary key,
  username   text unique not null,
  -- password di-hash dengan bcrypt, tapi untuk simplicity kita pakai SHA-256 check di JS
  -- Nilai default: username=admin, password=12345
  -- Ganti value ini setelah setup!
  pass_hash  text not null,
  created_at timestamptz default now()
);

-- Allow public to read admin_users hanya untuk login check (select by username only)
alter table public.admin_users enable row level security;
create policy "admin_login_check" on public.admin_users
  for select using (true);

